{
    "level": "A2–B1",
    "intro": "In this topic you will learn <strong>number words</strong>: <strong>much, many, a lot of, few, little</strong> - how to use them correctly with countable and uncountable nouns.",
    "rules": [
        {
            "label": "Many",
            "color": "emerald",
            "text": "<strong>Many</strong> - many (countable):",
            "example": "many books, many friends, many ideas"
        },
        {
            "label": "Much",
            "color": "blue",
            "text": "<strong>Much</strong> - many (uncountable):",
            "example": "much time, much money, much water"
        },
        {
            "label": "A lot of",
            "color": "amber",
            "text": "<strong>A lot of</strong> - a lot (both types):",
            "example": "a lot of books, a lot of time"
        }
    ]
}

{
    "title": "1. What are quantifiers?",
    "intro": "Quantifiers are words that indicate quantity:",
    "items": [
        {
            "label": "Much/Many",
            "title": "Many",
            "subtitle": "Much with uncountables, Many with countables"
        },
        {
            "label": "A lot of",
            "title": "Many (universal)",
            "subtitle": "Suitable for both types of nouns"
        },
        {
            "label": "Few/Little",
            "title": "Few",
            "subtitle": "Few with countables, Little with uncountable"
        }
    ]
}

{
    "title": "2. Many - with countable nouns",
    "sections": [
        {
            "label": "Rule",
            "color": "emerald",
            "description": "<strong>Many</strong> is used with <strong>plural countable nouns</strong>.",
            "examples": [
                {
                    "en": "many books",
                    "ua": "many books"
                },
                {
                    "en": "many friends",
                    "ua": "many friends"
                },
                {
                    "en": "many people",
                    "ua": "many people"
                },
                {
                    "en": "many ideas",
                    "ua": "many ideas"
                }
            ]
        },
        {
            "label": "In sentences",
            "color": "sky",
            "description": "Usage examples <strong>many</strong> in different types of sentences:",
            "examples": [
                {
                    "en": "How many books do you have?",
                    "ua": "How many books do you have?"
                },
                {
                    "en": "I don't have many friends here.",
                    "ua": "I don't have many friends here."
                },
                {
                    "en": "There are many people in the park.",
                    "ua": "There are many people in the park."
                },
                {
                    "en": "Do you have many questions?",
                    "ua": "Do you have many questions?"
                }
            ]
        },
        {
            "label": "Important!",
            "color": "amber",
            "description": "<strong>Many</strong> is more often used in <strong>questions and objections</strong>.",
            "examples": [
                {
                    "en": "❓ How many friends do you have?",
                    "ua": "Question"
                },
                {
                    "en": "❌ I don't have many books.",
                    "ua": "Objection"
                },
                {
                    "en": "✓ I have a lot of books. (assertion)",
                    "ua": "A lot of is better in affirmatives"
                }
            ],
            "note": "📌 In affirmative sentences it is better to use <strong>a lot of</strong>."
        }
    ]
}

{
    "title": "3. Much - with uncountable nouns",
    "sections": [
        {
            "label": "Rule",
            "color": "blue",
            "description": "<strong>Much</strong> is used with <strong>uncountable nouns</strong>.",
            "examples": [
                {
                    "en": "much time",
                    "ua": "much time"
                },
                {
                    "en": "much money",
                    "ua": "much money"
                },
                {
                    "en": "much water",
                    "ua": "much water"
                },
                {
                    "en": "much information",
                    "ua": "much information"
                }
            ]
        },
        {
            "label": "In sentences",
            "color": "sky",
            "description": "Examples of using <strong>much</strong> in different types of sentences:",
            "examples": [
                {
                    "en": "How much money do you need?",
                    "ua": "How much money do you need?"
                },
                {
                    "en": "I don't have much time today.[[[CODX_4]]]I don't have much time today.",
                    "ua": "У мене сьогодні небагато часу."
                },
                {
                    "en": "There isn't much water left.",
                    "ua": "There is not much water left."
                },
                {
                    "en": "Do you have much experience?",
                    "ua": "Do you have much experience?"
                }
            ]
        },
        {
            "label": "Important!",
            "color": "amber",
            "description": "<strong>Much</strong> is also more common in <strong>questions and objections</strong>.",
            "examples": [
                {
                    "en": "❓ How much time do you have?",
                    "ua": "Question"
                },
                {
                    "en": "❌ I don't have much money.",
                    "ua": "Objection"
                },
                {
                    "en": "✓ I have a lot of money. (assertion)",
                    "ua": "A lot of is better in affirmatives"
                }
            ],
            "note": "📌 In affirmative sentences it is better to use <strong>a lot of</strong>."
        }
    ]
}

{
    "title": "4. A lot of / Lots of - universal",
    "sections": [
        {
            "label": "With both types",
            "color": "purple",
            "description": "<strong>A lot of</strong> and <strong>lots of</strong> - universal, work with <strong>both types of nouns</strong>.",
            "examples": [
                {
                    "en": "a lot of books (countable)",
                    "ua": "many books (countable)"
                },
                {
                    "en": "a lot of time (uncountable)",
                    "ua": "a lot of time (uncountable)"
                },
                {
                    "en": "lots of friends",
                    "ua": "lots of friends"
                },
                {
                    "en": "lots of money",
                    "ua": "lots of money"
                }
            ]
        },
        {
            "label": "U affirmative",
            "color": "emerald",
            "description": "<strong>A lot of</strong> is best for <strong>affirmative sentences</strong>.",
            "examples": [
                {
                    "en": "I have a lot of friends.",
                    "ua": "I have a lot of friends."
                },
                {
                    "en": "She has a lot of time.",
                    "ua": "She has a lot of time."
                },
                {
                    "en": "We read a lot of books.",
                    "ua": " They drink a lot of water. here."
                },
                {
                    "en": "They drink a lot of water.",
                    "ua": "Вони пʼють багато води."
                }
            ]
        },
        {
            "label": "Lots of — неформальніше",
            "color": "sky",
            "description": "<strong>Lots of</strong> — більш неформальний варіант.",
            "examples": [
                {
                    "en": "I have lots of work to do.",
                    "ua": "У мене купа роботи."
                },
                {
                    "en": "There are lots of people here.",
                    "ua": "There are a lot of people here."
                }
            ],
            "note": "📌 <strong>A lot of</strong> is more neutral, <strong>lots of</strong> is more conversational."
        }
    ]
}

{
    "title": "5. Few - few (countable)",
    "sections": [
        {
            "label": "Few - few (negative)",
            "color": "rose",
            "description": "<strong>Few</strong> means <strong>few, not enough</strong> (negative tone).",
            "examples": [
                {
                    "en": "I have few friends here.",
                    "ua": "I have few friends here. (not enough)"
                },
                {
                    "en": "Few people know about it.",
                    "ua": "A few people know about it."
                },
                {
                    "en": "There are few books on the shelf.",
                    "ua": "A few books on the shelf."
                }
            ]
        },
        {
            "label": "A few (positive)",
            "color": "emerald",
            "description": "<strong>A few</strong> means <strong>a few, a little</strong> (positive tone).",
            "examples": [
                {
                    "en": "I have a few friends here.",
                    "ua": "I have a few friends here. (enough)"
                },
                {
                    "en": "A few people know about it.",
                    "ua": "Several people know about it."
                },
                {
                    "en": "I need a few minutes.",
                    "ua": "I need a few minutes."
                }
            ]
        },
        {
            "label": "Difference Few vs A Few",
            "color": "amber",
            "description": "Article <strong>a</strong> changes value!",
            "examples": [
                {
                    "en": "Few people came. ❌ (little, bad)",
                    "ua": "A few people came."
                },
                {
                    "en": "A few people came. ✓ (a few, good)",
                    "ua": "A few people came."
                }
            ],
            "note": "📌 <strong>Few</strong> = not enough, <strong>a few</strong> = enough."
        }
    ]
}

{
    "title": "6. Little - little (uncountable)",
    "sections": [
        {
            "label": "Little - little (negative)",
            "color": "rose",
            "description": "<strong>Little</strong> means <strong>little, not enough</strong> (negative tone).",
            "examples": [
                {
                    "en": "I have little time.",
                    "ua": "I have little time. (not enough)"
                },
                {
                    "en": "There is little water left.",
                    "ua": "We have little information."
                },
                {
                    "en": "We have little information.",
                    "ua": "We have little information."
                }
            ]
        },
        {
            "label": "A little (positive)",
            "color": "emerald",
            "description": "<strong>A little</strong> means <strong>little, little</strong> (positive tone).",
            "examples": [
                {
                    "en": "I have a little time.",
                    "ua": "I have a little time. (enough)"
                },
                {
                    "en": "There is a little water left.",
                    "ua": "I need a little help."
                },
                {
                    "en": "I need a little help.",
                    "ua": "I need a little help."
                }
            ]
        },
        {
            "label": "Difference Little vs A Little",
            "color": "amber",
            "description": "Article <strong>a</strong> changes the value!",
            "examples": [
                {
                    "en": "There is little hope. ❌ (little, bad)",
                    "ua": "There is a little hope."
                },
                {
                    "en": "There is a little hope. ✓ (a little, good)",
                    "ua": "There is a little hope."
                }
            ],
            "note": "📌 <strong>Little</strong> = not enough, <strong>a little</strong> = enough."
        }
    ]
}

{
    "title": "7. Some / Any — some amount",
    "sections": [
        {
            "label": "Some - in affirmative",
            "color": "sky",
            "description": "<strong>Some</strong> - for both types in <strong>affirmative sentences</strong>.",
            "examples": [
                {
                    "en": "I have some books.",
                    "ua": "I have some books."
                },
                {
                    "en": "She has some money.",
                    "ua": "She has some money."
                },
                {
                    "en": "We need some time.",
                    "ua": "We need some time."
                }
            ]
        },
        {
            "label": "Any - in questions and objections",
            "color": "purple",
            "description": "<strong>Any</strong> - for both types in <strong>questions and objections objections.",
            "examples": [
                {
                    "en": "Do you have any questions?",
                    "ua": "Do you have any questions?"
                },
                {
                    "en": "I don't have any money.",
                    "ua": "I don't have any money."
                },
                {
                    "en": "Is there any water?",
                    "ua": " water?"
                }
            ]
        },
        {
            "label": "Versatility",
            "color": "emerald",
            "description": "<strong>Some/Any</strong> work with both types of nouns.",
            "examples": [
                {
                    "en": "some books / some water",
                    "ua": "some books / some water"
                },
                {
                    "en": "any friends / any time",
                    "ua": "some friends / any time"
                }
            ]
        }
    ]
}

{
    "title": "8. Comparison table",
    "intro": "Basic quantifiers and their use:",
    "rows": [
        {
            "en": "Many",
            "ua": "Many (countable)",
            "note": "many books, many friends (question/objection)"
        },
        {
            "en": "Much",
            "ua": "Much (uncountable)",
            "note": "much time, much money (question/objection)"
        },
        {
            "en": "A lot of / Lots of",
            "ua": "Many (both types)",
            "note": "a lot of books/time (esp. assertion)"
        },
        {
            "en": "Few",
            "ua": "Few (countable, negative)",
            "note": "few people (not enough)"
        },
        {
            "en": "A few",
            "ua": "A few (countable, positive)",
            "note": "a few friends (enough)"
        },
        {
            "en": "Little",
            "ua": "Little (uncountable, negative)",
            "note": "little time (not enough)"
        },
        {
            "en": "A little",
            "ua": "A little (uncountable, positive)",
            "note": "a little water (enough)"
        }
    ],
    "warning": "📌 The article <strong>a</strong> before few/little changes the meaning from negative to positive!"
}

{
    "title": "9. Typical errors",
    "items": [
        {
            "label": "Error 1",
            "color": "rose",
            "title": "Much with countable nouns.",
            "wrong": "I have many books.",
            "right": "​​​​ <span class="font-mono">I have many books. / I have a lot of books.</span>"
        },
        {
            "label": "Error 2",
            "color": "amber",
            "title": "Many with uncountable nouns.",
            "wrong": "I don't have many time.[[[CODX_19]]]​​​​ time.</span>",
            "right": "✅ <span class="font-mono">I don't have much time.</span>"
        },
        {
            "label": "Error 3",
            "color": "sky",
            "title": "Forgetting the article a before few/little.",
            "wrong": "I have few time. (incorrect value)",
            "right": " ✅ <span class="font-mono">I have a little time. (positive value)</span>"
        },
        {
            "label": "Error 4",
            "color": "purple",
            "title": "Many/much in the affirmative.",
            "wrong": "I have many friends. (better otherwise)",
            "right": "​​​​ <span class="font-mono">I have a lot of friends. (more natural)</span>"
        }
    ]
}

{
    "title": "11. Practice",
    "select_title": "Exercise 1. Choose the correct quantifier",
    "select_intro": "Choose the correct quantity word for each sentence.",
    "selects": [
        {
            "label": "I don't have ___ time. (much / many)",
            "prompt": "What is the quantifier?"
        },
        {
            "label": "How ___ books do you have? (much / many)",
            "prompt": "What is the quantifier?"
        },
        {
            "label": "She has ___ friends. (a lot of / much)",
            "prompt": "What is the quantifier?"
        },
        {
            "label": "There is ___ water left. (few/little) do.",
            "prompt": "Який квантифікатор?"
        }
    ],
    "options": [
        "Перший варіант",
        "Другий варіант"
    ],
    "input_title": "Вправа 2. Заповни пропуски",
    "input_intro": "Напиши many, much, або a lot of.",
    "inputs": [
        {
            "before": "I have ___ work to do.",
            "after": "→"
        },
        {
            "before": "How ___ money do you need?",
            "after": "→"
        },
        {
            "before": "There are ___ people here.",
            "after": "→"
        }
    ],
    "rephrase_title": "Exercise 3. Error correction",
    "rephrase_intro": "Find and correct the error with the quantifier.",
    "rephrase": [
        {
            "example_label": "Example:",
            "example_original": "I have many books.",
            "example_target": "I have many books. / I have a lot of books."
        },
        {
            "original": "1. She doesn't have many time.",
            "placeholder": "Fix the error"
        },
        {
            "original": "2. There are many people in the room.",
            "placeholder": "Correct the error"
        }
    ]
}

{
    "title": "Other pages from the category Nouns, articles and quantity",
    "items": [
        {
            "label": "Quantifiers — Much, Many, A Lot, Few, Little",
            "current": true
        },
        {
            "label": "Articles A / An / The — Articles",
            "current": false
        },
        {
            "label": "Zero Article — Zero article",
            "current": false
        },
        {
            "label": "Plural Nouns",
            "current": false
        }
    ]
}
